pub async fn logs(
        &self,
        spoke_name: &str,
        follow: bool,
        tail: u32,
    ) -> Result<impl futures_util::Stream<Item = std::result::Result<bollard::container::LogOutput, bollard::errors::Error>>>
    {
        let options = LogsOptionsBuilder::new()
            .follow(follow)
            .stdout(true)
            .stderr(true)
            .tail(&tail.to_string())
            .build();

        Ok(self.docker.logs(spoke_name, Some(options)))
    }
